import React, { useEffect, useState } from "react";
import { Box, Typography, Card, Table, TableBody, TableCell, TableContainer,
  TableHead, TableRow, Paper, Button, CircularProgress, Alert, Tabs, Tab } from "@mui/material";
import { Person, People, DirectionsCar, PendingActions, LocalTaxi } from "@mui/icons-material";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API = process.env.REACT_APP_API_URL + "/admin";

const overviewIcons = {
  users: { icon: <Person fontSize="large" />, color: "#3f51b5" },
  riders: { icon: <People fontSize="large" />, color: "#4caf50" },
  captains: { icon: <DirectionsCar fontSize="large" />, color: "#ff9800" },
  pendingCaptains: { icon: <PendingActions fontSize="large" />, color: "#f44336" },
  rides: { icon: <LocalTaxi fontSize="large" />, color: "#9c27b0" },
};

export default function AdminDashboard() {
  const [overview, setOverview] = useState({ users:0, riders:0, captains:0, pendingCaptains:0, rides:0 });
  const [users, setUsers] = useState([]);
  const [captains, setCaptains] = useState([]);
  const [pending, setPending] = useState([]);
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [tab, setTab] = useState("overview");
  const navigate = useNavigate();

  const token = localStorage.getItem("token");
  const headers = { Authorization: `Bearer ${token}` };

  const fetchData = async () => {
    setLoading(true);
    setError("");
    try {
      const [overviewRes, usersRes, captainsRes, pendingRes, ridesRes] = await Promise.all([
        axios.get(`${API}/overview`, { headers }),
        axios.get(`${API}/users`, { headers }),
        axios.get(`${API}/captains`, { headers }),
        axios.get(`${API}/pending-captains`, { headers }),
        axios.get(`${API}/rides`, { headers }),
      ]);
      setOverview(overviewRes.data);
      setUsers(usersRes.data.users);
      setCaptains(captainsRes.data.captains);
      setPending(pendingRes.data.pendingCaptains);
      setRides(ridesRes.data.rides);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to fetch data");
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleApprove = async (id) => { await axios.post(`${API}/captain/${id}/approve`, {}, { headers }); fetchData(); };
  const handleReject = async (id) => { await axios.post(`${API}/captain/${id}/reject`, {}, { headers }); fetchData(); };
  const handleLogout = () => { localStorage.removeItem("token"); localStorage.removeItem("role"); navigate("/admin"); window.location.reload(); };
  const formatLabel = (key) => key.replace(/([A-Z])/g, " $1").replace(/^./, s=>s.toUpperCase());

  return (
    <Box p={4}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Typography variant="h4" fontWeight="bold">Admin Dashboard</Typography>
        <Button variant="contained" color="error" onClick={handleLogout}>Logout</Button>
      </Box>

      <Tabs value={tab} onChange={(e,val)=>setTab(val)} sx={{mb:3}}>
        <Tab label="Overview" value="overview" />
        <Tab label="Users" value="users" />
        <Tab label="Captains" value="captains" />
        <Tab label="Pending Captains" value="pending" />
        <Tab label="Rides" value="rides" />
      </Tabs>

      {loading && <Box display="flex" justifyContent="center" my={2}><CircularProgress /></Box>}
      {error && <Alert severity="error" sx={{mb:2}}>{error}</Alert>}

      {/* Overview Cards */}
      {tab==="overview" && (
        <Box display="flex" flexWrap="wrap" gap={3} justifyContent="center">
          {Object.entries(overview).map(([key,value])=>(
            <Card key={key} sx={{ textAlign:"center", py:3, px:2, minWidth:150, maxWidth:220 }}>
              <Box mb={1} color={overviewIcons[key]?.color} display="flex" justifyContent="center">{overviewIcons[key]?.icon}</Box>
              <Typography variant="subtitle1" color="textSecondary">{formatLabel(key)}</Typography>
              <Typography variant="h4" fontWeight="bold">{value}</Typography>
            </Card>
          ))}
        </Box>
      )}

      {/* Users Table */}
      {tab==="users" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead><TableRow><TableCell>Full Name</TableCell><TableCell>Email</TableCell><TableCell>Mobile</TableCell><TableCell>Role</TableCell><TableCell>Status</TableCell></TableRow></TableHead>
            <TableBody>{users.length>0 ? users.map(u=>(<TableRow key={u._id}><TableCell>{u.fullName}</TableCell><TableCell>{u.email}</TableCell><TableCell>{u.mobile}</TableCell><TableCell>{u.role}</TableCell><TableCell>{u.approvalStatus||"-"}</TableCell></TableRow>)) : <TableRow><TableCell colSpan={5} align="center">No users found</TableCell></TableRow>}</TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Approved Captains */}
      {tab==="captains" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead><TableRow><TableCell>Name</TableCell><TableCell>Email</TableCell><TableCell>Documents</TableCell><TableCell>Status</TableCell></TableRow></TableHead>
            <TableBody>{captains.length>0 ? captains.map(c=>(<TableRow key={c._id}><TableCell>{c.fullName}</TableCell><TableCell>{c.email}</TableCell><TableCell>{c.documents?.map((d,i)=>(<Box key={i}><a href={d.file} target="_blank">{d.type}</a></Box>))||"-"}</TableCell><TableCell>{c.approvalStatus}</TableCell></TableRow>)) : <TableRow><TableCell colSpan={4} align="center">No captains found</TableCell></TableRow>}</TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Pending Captains */}
      {tab==="pending" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead><TableRow><TableCell>Name</TableCell><TableCell>Email</TableCell><TableCell>Status</TableCell><TableCell>Actions</TableCell></TableRow></TableHead>
            <TableBody>{pending.length>0 ? pending.map(p=>(<TableRow key={p._id}><TableCell>{p.fullName}</TableCell><TableCell>{p.email}</TableCell><TableCell>{p.approvalStatus}</TableCell><TableCell><Button color="success" variant="contained" sx={{mr:1}} onClick={()=>handleApprove(p._id)}>Approve</Button><Button color="error" variant="contained" onClick={()=>handleReject(p._id)}>Reject</Button></TableCell></TableRow>)) : <TableRow><TableCell colSpan={4} align="center">No pending captains</TableCell></TableRow>}</TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Rides */}
      {tab==="rides" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead><TableRow><TableCell>Rider</TableCell><TableCell>Captain</TableCell><TableCell>Pickup</TableCell><TableCell>Drop</TableCell><TableCell>Fare</TableCell><TableCell>Status</TableCell></TableRow></TableHead>
            <TableBody>{rides.length>0 ? rides.map(r=>(<TableRow key={r._id}><TableCell>{r.riderId?.fullName||"-"}</TableCell><TableCell>{r.captainId?.fullName||"-"}</TableCell><TableCell>{r.pickup}</TableCell><TableCell>{r.drop}</TableCell><TableCell>{r.fare||"-"}</TableCell><TableCell>{r.status}</TableCell></TableRow>)) : <TableRow><TableCell colSpan={6} align="center">No rides found</TableCell></TableRow>}</TableBody>
          </Table>
        </TableContainer>
      )}

    </Box>
  );
}
